// Create struct for drive status data
typedef struct _DriveStatus
{
    // status values from controller IOs
    BOOL* BrakeFeedback;
    S16* MotorTemp;

    // status data from motor drives
    BOOL* DriveOn;
    BOOL* DriveReady;
    BOOL* Running;
    BOOL* Fault;
    BOOL* EmStopCoast;
    BOOL* EmStop;
    BOOL* Inhibit;
    BOOL* Warning;
    BOOL* AtSpeed;
    BOOL* Overspeed;
    BOOL* FieldbusControl;
    BOOL* Watchdog;

    S16* SpeedPct;
    S16* SpeedRpm;
    S16* Torque;
    S16* Current;
    S16* Rotations;
    S16* DriveTemp;
    S16* ActiveFault;

    U16* StatusWord;     // Status Word is extracted into BOOL variables in program ReadStatuslWord()
} DriveStatus;

// Create struct for drive control data
typedef struct _DriveControl
{
    // variables controlling controller IOs
    BOOL  Brake;         // brake control variable for program INTERNAL USE
    BOOL* BrakeDO;       // digital output to brake control; THIS IS NOT USED IN CONTROL FUNCTIONS TO CONTROL BRAKE; used only in MotorBrakeControl() function
    BOOL* BrakeService;
    BOOL* FanDO;         // digital output to fan control
    BOOL* FanService;

    // control data to motor drives
    BOOL* DriveOn;
    BOOL* Run;
    BOOL* Reset;
    BOOL* EMStopCoast;
    BOOL* EMStop;
    BOOL* RampInToZero;
    BOOL* RampOutToZero;
    BOOL* RampHold;
    BOOL* Inching1;
    BOOL* Inching2;
    BOOL* FieldbusControl;
    BOOL* Watchdog;

    S16* TorqueLimMotor;
    S16* TorqueLimGen;
    S16* SpeedPctSP;

    U16* ControlWord; // Control Word is combined from BOOL variables in program WriteControlWord()
} DriveControl;

// Define yaw motor structure
typedef struct _YawMotorStruct
{
    BOOL* ServiceMode;          // when service mode is active, motor can be only controlled in service menu
    BOOL* MotorEnable;
    U8* BrakeMode;
    U8* MotorState;
    char* MotorStateTxt;
    S16 MotorTargetSpeedPct;      // yaw motor running speed target setpoint - actual control value(SpeedPctSP) to motor drive will be ramped based on this value
    S16 MotorTorqueLimMotor;
    S16 MotorTorqueLimGen;
    DriveStatus* Status;
    DriveControl* Control;
    U32* CANopenState;
    char* CANopenStateTxt;

    S32 MotorPosition_Initial;   // this value is set during initialization and holds revolutions count for yaw angle calculation reference
    S32* MotorPosition;          // motor position in revolutions, that is value received from drive
    S32 MotorPosition_Offset;    // motor position offset in revolutions, this value is used to "reset" motor position variable in controller
    U8 resetCount;               // counts retry attempts for automatic drive reset
} YawMotor;


// create array of yaw motor structures
static YawMotor myMotors[MOTOR_COUNT];
// create array of yaw motor status data structures
static DriveStatus myDriveStatus[MOTOR_COUNT];
// create array of yaw motor control data structures
static DriveControl myDriveControl[MOTOR_COUNT];

