static void Initialize_Comm()
{
    // start CANopen communication
    V_YawMotorCANopenStartStopCom = 1;
}


static void Initialize_Drive(U8 driveID)
{
    // Set bits that are not used for control
    *myMotors[driveID].Control->EMStopCoast = true;
    *myMotors[driveID].Control->EMStop = true;
    *myMotors[driveID].Control->RampOutToZero = true;
    *myMotors[driveID].Control->RampHold = true;
    *myMotors[driveID].Control->RampInToZero = true;
    *myMotors[driveID].Control->Inching1 = false;
    *myMotors[driveID].Control->Inching2 = false;
    *myMotors[driveID].Control->FieldbusControl = true;

    *myMotors[driveID].Control->DriveOn = true;
}


static void Initialize_Drives()
{
    // set drives to ready state
    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        Initialize_Drive(i);
    }
}


static STATUS Initialize()
{
    STATUS LocalStatus = 0;

    LocalStatus = LoadParameters();
    if (LocalStatus != 0) { return LocalStatus; }
    Initialize_MotorStructs();
    Initialize_Comm();
    Initialize_Drives();

    LocalStatus = LoadMotorGroupSetup();
    if (LocalStatus != OS_SUCCESS) { return LocalStatus; }

    MotorControlLog = CustomLog_New("B_YAWM_MotorControlLog", 100, 81);
    if (MotorControlLog == NULL)
    {
        AppSystemLog(0, "Can not create MotorControlLog");
        return -167;
    }


    // INITIALIZE MotorTargetSpeedPct values
    //--------------------------------------------------------------------
    myMotors[0].MotorTargetSpeedPct = 0;
    myMotors[1].MotorTargetSpeedPct = 0;
    myMotors[2].MotorTargetSpeedPct = 0;
    myMotors[3].MotorTargetSpeedPct = 0;
    myMotors[4].MotorTargetSpeedPct = 0;
    myMotors[5].MotorTargetSpeedPct = 0;
    myMotors[6].MotorTargetSpeedPct = 0;
    myMotors[7].MotorTargetSpeedPct = 0;



    // INITIALIZE resetCount values
    //--------------------------------------------------------------------
    myMotors[0].resetCount = 0;
    myMotors[1].resetCount = 0;
    myMotors[2].resetCount = 0;
    myMotors[3].resetCount = 0;
    myMotors[4].resetCount = 0;
    myMotors[5].resetCount = 0;
    myMotors[6].resetCount = 0;
    myMotors[7].resetCount = 0;


    // clear motors rotations variables - important for detecting when motor has sent rotation data first time
    //--------------------------------------------------------------------
    *myMotors[0].Status->Rotations = 0;
    *myMotors[1].Status->Rotations = 0;
    *myMotors[2].Status->Rotations = 0;
    *myMotors[3].Status->Rotations = 0;
    *myMotors[4].Status->Rotations = 0;
    *myMotors[5].Status->Rotations = 0;
    *myMotors[6].Status->Rotations = 0;
    *myMotors[7].Status->Rotations = 0;
    myMotors[0].MotorPosition_Initial = 0;
    myMotors[1].MotorPosition_Initial = 0;
    myMotors[2].MotorPosition_Initial = 0;
    myMotors[3].MotorPosition_Initial = 0;
    myMotors[4].MotorPosition_Initial = 0;
    myMotors[5].MotorPosition_Initial = 0;
    myMotors[6].MotorPosition_Initial = 0;
    myMotors[7].MotorPosition_Initial = 0;

    return OS_SUCCESS;
}


//-----------------------------------------------------------------------
// CONTROL                CONTROL                 CONTROL
//-----------------------------------------------------------------------

static STATUS LoadParameters()
{
    STATUS LocalStatus = 0;

    LocalStatus = OS_VarDB_ReadVariableByName("P_YAWM_MotTempInputParRes", &P_YAWM_MotTempInputParRes, sizeof(P_YAWM_MotTempInputParRes), NULL);
    if (LocalStatus != 0) { return LocalStatus; }
    LocalStatus = OS_VarDB_ReadVariableByName("P_YAWM_MotTempInputSerRes", &P_YAWM_MotTempInputSerRes, sizeof(P_YAWM_MotTempInputSerRes), NULL);
    if (LocalStatus != 0) { return LocalStatus; }

    // calculate deg/ohm gain for PT100 values
    GainPT100 = (YAWM_PT100_MAXTEMP - YAWM_PT100_MINTEMP) / (YAWM_PT100_MAXRES - YAWM_PT100_MINRES);


    /*
    //********************************************************************************
    //  CALCULATE MIN AND MAX REAL TEMP. AND THEN BASED ON THESE THE GAIN VALUE
    //********************************************************************************
    F32 resistance;
    // calculate measured total circuit resistance for controller temp reading of YAWM_PT100_MINTEMP
    resistance = YAWM_PT100_MINRES + (YAWM_PT100_MINTEMP - YAWM_PT100_MINTEMP) / GainPT100;
    OS_com_printf("resistance 1: %f\n", resistance);
    // calculate equivalent PT100 resistance
    resistance = ( ( 1 / (1 / resistance - 1 / P_YAWM_MotTempInputParRes) ) - P_YAWM_MotTempInputSerRes ) / 3;
    OS_com_printf("resistance 2: %f\n", resistance);
    // calculate resulting PT100 temperature
    RealTempMin = YAWM_PT100_MINTEMP + (resistance - YAWM_PT100_MINRES) * GainPT100;
    OS_com_printf("RealTempMin: %f\n", RealTempMin);

    // calculate measured total circuit resistance for controller temp reading of YAWM_PT100_MAXTEMP
    resistance = YAWM_PT100_MINRES + (YAWM_PT100_MAXTEMP - YAWM_PT100_MINTEMP) / GainPT100;
    OS_com_printf("resistance 1: %f\n", resistance);
    // calculate equivalent PT100 resistance
    resistance = ( ( 1 / (1 / resistance - 1 / P_YAWM_MotTempInputParRes) ) - P_YAWM_MotTempInputSerRes ) / 3;
    OS_com_printf("resistance 2: %f\n", resistance);
    // calculate resulting PT100 temperature
    F32 RealTempMax = YAWM_PT100_MINTEMP + (resistance - YAWM_PT100_MINRES) * GainPT100;
    OS_com_printf("RealTempMax: %f\n", RealTempMax);

    // calculate gain
    RealTempCalcGain = (YAWM_PT100_MAXTEMP - YAWM_PT100_MINTEMP) / (RealTempMax - RealTempMin);
    OS_com_printf("RealTempCalcGain: %f\n", RealTempCalcGain);
    //********************************************************************************
    //********************************************************************************
    */

    return LocalStatus;
}


