// Check the communication and status of all yaw drives
static void Check_Drives()
{
    U8 failCount = 0;
    U8 disabledCount = 0;
    U8 notreadyCount = 0;
    U8 nocomCount = 0;


    CheckCommunication();


    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorEnable && *myMotors[i].MotorState != YAWM_MOTOR_NOCOM)
        {
            if (*myMotors[i].Status->Fault)// || !*myMotors[i].Status->DriveOn)
            {
                failCount++;
                *myMotors[i].MotorState = YAWM_MOTOR_FAULT;
                sprintf(myMotors[i].MotorStateTxt, "FAULT");
            }
            else if (*myMotors[i].Status->DriveReady)
            {
                *myMotors[i].MotorState = YAWM_MOTOR_READY;
                sprintf(myMotors[i].MotorStateTxt, "READY");
                V_YAWM_Fault = false;
            }
            else
            {
                notreadyCount++;
                *myMotors[i].MotorState = YAWM_MOTOR_NOTREADY;
                sprintf(myMotors[i].MotorStateTxt, "NOT READY");
            }
        }
        else if (!*myMotors[i].MotorEnable)
        {
            disabledCount++;
            *myMotors[i].MotorState = YAWM_MOTOR_DISABLED;
            sprintf(myMotors[i].MotorStateTxt, "DISABLED");

            if (*myMotors[i].Control->Run) { *myMotors[i].Control->Run = false; }   // stop motor if it is running and gets disabled
        }
        else
        {
            nocomCount++;
        }
    }

    MotorsEnabledCount = MOTOR_COUNT - disabledCount;

    if (failCount > 0 || nocomCount > 0)   // FAULT
    {
        V_YAWM_Fault = true;
        V_YAWM_Ready = false;
        return;
    }
    else if (notreadyCount > 0 || (MOTOR_COUNT - disabledCount) < P_YAWM_EnabledMotorsMin)   // NOT READY
    {
        V_YAWM_Fault = false;
        V_YAWM_Ready = false;
        return;
    }
    else
    {
        V_YAWM_Fault = false;
        V_YAWM_Ready = true;
    }
}


//**************************************************************
// Check converters error codes and manage error logging
//**************************************************************
void DriveError_Log()
{
    static S16 Error_Prev[MOTOR_COUNT];      // stores previously read error codes to detect changes in error code

    // Check each drive error codes
    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        // check for new error code
        if (*myMotors[i].Status->ActiveFault != Error_Prev[i] && *myMotors[i].Status->ActiveFault != 0)
        {
            char ErrorDescriptionString[81];
            snprintf(ErrorDescriptionString, sizeof(ErrorDescriptionString), "Drive %u, %3d-%s", (i + 1), *myMotors[i].Status->ActiveFault, ERROR_CODES_GetDescription(myMotors[i].Status->ActiveFault));
            CustomLog_MakeEntry(MotorControlLog, &ErrorDescriptionString);

            Error_Prev[i] = *myMotors[i].Status->ActiveFault;
        }
    }
}

void SysError_Log()
{
    static U8 MotorState_Prev[MOTOR_COUNT];

    // Check each motor state
    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorState != MotorState_Prev[i])
        {
            if (*myMotors[i].MotorState == YAWM_MOTOR_NOTREADY)
            {
                char ErrorDescriptionString[81];
                snprintf(ErrorDescriptionString, sizeof(ErrorDescriptionString), "Motor %u not ready", (i + 1));
                CustomLog_MakeEntry(MotorControlLog, &ErrorDescriptionString);
            }

            MotorState_Prev[i] = *myMotors[i].MotorState;
        }
    }
}

void MotorControl_Log()
{
    // check if command is set, to clear error log
    if (V_YAWM_ClearErrorLog)
    {
        CustomLog_ClearAll(MotorControlLog);
        V_YAWM_ClearErrorLog = false;
        OS_VarDB_UpdateVariableByName("V_YAWM_ClearErrorLog", &V_YAWM_ClearErrorLog, sizeof(V_YAWM_ClearErrorLog));

        return;
    }

    DriveError_Log();
    SysError_Log();
}


// Calculate motor position using actual motor speed value
static void CalcMotorPosition()
{
    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        *myMotors[i].MotorPosition = *myMotors[i].Status->Rotations + myMotors[i].MotorPosition_Offset;
    }
}


// Reset one motor position
void ResetMotorPosition(U8 motorID)
{
    myMotors[motorID].MotorPosition_Offset = -(*myMotors[motorID].Status->Rotations);
    *myMotors[motorID].MotorPosition = 0;
}


// Reset all motor position values
void ResetAllMotorPositions()
{
    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        myMotors[i].MotorPosition_Offset = -(*myMotors[i].Status->Rotations);
        *myMotors[i].MotorPosition = 0;
    }
}


// Returns num of motors which position is beyond given limit in [1 rev]
U8 CheckAllMotorPositions(S32 positionLimit)
{
    U8 count = 0;

    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorEnable)
        {
            if (*myMotors[i].MotorPosition > positionLimit || *myMotors[i].MotorPosition < -positionLimit)
            {
                count++;
            }
        }
    }

    return count;
}


// Get maximum actual speed of all enabled motors in %; returns absolute value without direction sign
S16 GetMaxSpeedPct()
{
    S16 maxSpeed = 0;

    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorEnable && *myMotors[i].Status->SpeedPct > 0)   // for positive speed
        {
            if (*myMotors[i].Status->SpeedPct > maxSpeed)
            {
                maxSpeed = *myMotors[i].Status->SpeedPct;
            }
        }
        else if (*myMotors[i].MotorEnable && *myMotors[i].Status->SpeedPct < 0) // for negative speed
        {
            if (-(*myMotors[i].Status->SpeedPct) > maxSpeed)
            {
                maxSpeed = -(*myMotors[i].Status->SpeedPct);
            }
        }
    }

    return maxSpeed;
}


// Get maximum actual speed of all enabled motors in RPM; returns absolute value without direction sign
S16 GetMaxSpeedRpm()
{
    S16 maxSpeed = 0;

    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorEnable && *myMotors[i].Status->SpeedRpm > 0)   // for positive speed
        {
            if (*myMotors[i].Status->SpeedRpm > maxSpeed)
            {
                maxSpeed = *myMotors[i].Status->SpeedRpm;
            }
        }
        else if (*myMotors[i].MotorEnable && *myMotors[i].Status->SpeedRpm < 0) // for negative speed
        {
            if (-(*myMotors[i].Status->SpeedRpm) > maxSpeed)
            {
                maxSpeed = -(*myMotors[i].Status->SpeedRpm);
            }
        }
    }

    return maxSpeed;
}


// Get motors actual running direction
// Returns: 0 - NA; 1 - CCW; 2 - CW
U8 GetRunDirection()
{
    S16 maxSpeedPos = 0;
    S16 maxSpeedNeg = 0;

    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorEnable && *myMotors[i].Status->SpeedRpm > 0)   // for positive speed
        {
            if (*myMotors[i].Status->SpeedRpm > maxSpeedPos)
            {
                maxSpeedPos = *myMotors[i].Status->SpeedRpm;
            }
        }
        else if (*myMotors[i].MotorEnable && *myMotors[i].Status->SpeedRpm < 0) // for negative speed
        {
            if (*myMotors[i].Status->SpeedRpm < maxSpeedNeg)
            {
                maxSpeedNeg = *myMotors[i].Status->SpeedRpm;
            }
        }
    }

    if (maxSpeedPos > -maxSpeedNeg)
    {
        return 2;
    }
    else if (maxSpeedPos < -maxSpeedNeg)
    {
        return 1;
    }

    return 0;
}


// Returns num of motors which run faster than given speed limit
U8 CheckMotorsSpeedPct(S16 speedLimitPct)
{
    U8 count = 0;

    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorEnable)
        {
            if (*myMotors[i].Status->SpeedPct > speedLimitPct || *myMotors[i].Status->SpeedPct < -speedLimitPct)
            {
                count++;
            }
        }
    }

    return count;
}


// Returns num of motors which run faster than given speed limit
U8 CheckMotorsSpeedRpm(S16 speedLimitRpm)
{
    U8 count = 0;

    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorEnable)
        {
            if (*myMotors[i].Status->SpeedRpm > speedLimitRpm || *myMotors[i].Status->SpeedRpm < -speedLimitRpm)
            {
                count++;
            }
        }
    }

    return count;
}


