// Set speed and torque for specific yaw drive
static void Set_OneMotorSpeedAndTorque(U8 motorID, S16 Speed/*[0,01%]*/, S16 TorqueM/*[0,1%]*/, S16 TorqueG/*[0,1%]*/)
{
    if (*myMotors[motorID].ServiceMode) { return; } // motor in service mode

    if (*myMotors[motorID].MotorEnable)
    {
        myMotors[motorID].MotorTargetSpeedPct = Speed;
        myMotors[motorID].MotorTorqueLimMotor = TorqueM;
        myMotors[motorID].MotorTorqueLimGen = TorqueG;
    }
}

// Set speed and torque for all yaw drives
void Set_AllMotorsSpeedAndTorque(S16 Speed/*[0,01%]*/, S16 TorqueM/*[0,1%]*/, S16 TorqueG/*[0,1%]*/)
{
    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        Set_OneMotorSpeedAndTorque(i, Speed, TorqueM, TorqueG);
    }
}

// Set speed and torque for motors in group 1
void Set_Group1MotorsSpeedAndTorque(S16 Speed/*[0,01%]*/, S16 TorqueM/*[0,1%]*/, S16 TorqueG/*[0,1%]*/)
{
    if (shutdown_Flag) { return; }

    U8 i;
    for (i = 0; i < MOTOR_COUNT / 2; i++)
    {
        Set_OneMotorSpeedAndTorque(YawMotorGroup1[i], Speed, TorqueM, TorqueG);
    }
}

// Set speed and torque for motors in group 2
void Set_Group2MotorsSpeedAndTorque(S16 Speed/*[0,01%]*/, S16 TorqueM/*[0,1%]*/, S16 TorqueG/*[0,1%]*/)
{
    if (shutdown_Flag) { return; }

    U8 i;
    for (i = 0; i < MOTOR_COUNT / 2; i++)
    {
        Set_OneMotorSpeedAndTorque(YawMotorGroup2[i], Speed, TorqueM, TorqueG);
    }
}


// Set speed and torque for all yaw drives WITHOUT speed RAMPING
void Set_AllMotorsSpeedAndTorqueNoRamp(S16 Speed/*[0,01%]*/, S16 TorqueM/*[0,1%]*/, S16 TorqueG/*[0,1%]*/)
{
    if (shutdown_Flag) { return; }

    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorEnable && !*myMotors[i].ServiceMode)
        {
            *myMotors[i].Control->SpeedPctSP = Speed;
            myMotors[i].MotorTargetSpeedPct = Speed;

            myMotors[i].MotorTorqueLimMotor = TorqueM;
            myMotors[i].MotorTorqueLimGen = TorqueG;
        }
    }
}


// This function starts specific yaw motor
// This function can be called only once, but additional information can be retrieved, if called more.
// Each time set "firstentry" to TRUE for first call. For following calls, set it to FALSE.
// RETURN:
//    0-IN PROGRESS; 1-SUCCESS ; negative num-FAULT CODE
int Run_OneMotor(BOOL firstentry, U8 motorID)
{
    if (*myMotors[motorID].ServiceMode) { return -10; } // motor in service mode

    if (firstentry)
    {
        motor_processTimer[motorID] = YAWM_RUN_DELAY;
    }

    if (*myMotors[motorID].MotorEnable)
    {
        if (!*myMotors[motorID].Control->Run)
        {
            *myMotors[motorID].Control->Run = true;
        }
        //else if (*myMotors[motorID].Status->SpeedPct < -P_YAWM_MinSpeedPct && *myMotors[motorID].Status->SpeedPct > P_YAWM_MinSpeedPct) // wait till running faster than min speed
        else if (*myMotors[motorID].Status->Running)
        {
            return 1;   // SUCCESS
        }

        motor_processTimer[motorID] -= YAWM_TASK_SCANTIME;
        if (motor_processTimer[motorID] > 0) { return 0; }     // IN PROGRESS
        else
        {
            char ErrorDescriptionString[81];
            snprintf(ErrorDescriptionString, sizeof(ErrorDescriptionString), "Run motor %u - Timeout", (motorID + 1));
            CustomLog_MakeEntry(MotorControlLog, &ErrorDescriptionString);
            return -1;  // FAULT - timeout
        }
    }
    else
    {
        char ErrorDescriptionString[81];
        snprintf(ErrorDescriptionString, sizeof(ErrorDescriptionString), "Can't run motor %u - Disabled", (motorID + 1));
        CustomLog_MakeEntry(MotorControlLog, &ErrorDescriptionString);
        return -2;  // FAULT - can not run, motor not enabled
    }
}


// This function stops specific yaw motor by ramping to min speed.
// This function should be called as long as it returns 0
// Each time set "firstentry" to TRUE for first call. For following calls, set it to FALSE.
// Returns 1 when motor status RUN signal becomes false.
// RETURN:
//    0-IN PROGRESS; 1-SUCCESS; negative num-FAULT CODE
int Stop_OneMotor(BOOL firstentry, U8 motorID)
{
    if (*myMotors[motorID].ServiceMode) { return -10; } // motor in service mode

    if (firstentry)
    {
        motor_processTimer[motorID] = YAWM_STOP_DELAY;
        myMotors[motorID].MotorTargetSpeedPct = 0;
    }

    if (*myMotors[motorID].MotorEnable)
    {
        if (*myMotors[motorID].Control->Run && *myMotors[motorID].Control->SpeedPctSP < P_YAWM_MinSpeedPct && *myMotors[motorID].Control->SpeedPctSP > -P_YAWM_MinSpeedPct) // wait till speed setpoint ramped down
        {
            *myMotors[motorID].Control->Run = false;
        }
        //if (*myMotors[motorID].Status->SpeedPct > -P_YAWM_MinSpeedPct && *myMotors[motorID].Status->SpeedPct < P_YAWM_MinSpeedPct) // wait till slowed down to min speed
        else if (!*myMotors[motorID].Status->Running)
        {
            return 1;   // SUCCESS
        }

        motor_processTimer[motorID] -= YAWM_TASK_SCANTIME;
        if (motor_processTimer[motorID] > 0) { return 0; }   // IN PROGRESS
        else
        {
            *myMotors[motorID].Control->Run = false;    // still deactivate motor run signal when process timeout occurrs

            char ErrorDescriptionString[81];
            snprintf(ErrorDescriptionString, sizeof(ErrorDescriptionString), "Stop motor %u - Timeout", (motorID + 1));
            CustomLog_MakeEntry(MotorControlLog, &ErrorDescriptionString);
            return -1;  // FAULT - timeout
        }
    }
    else
    {
        *myMotors[motorID].Control->Run = false;
        return 1;   // SUCCESS
    }
}


// This function stops specific yaw motor without waiting it to slow down
// This function can be called as long as it returns 0
// Each time set "firstentry" to TRUE for first call. For following calls, set it to FALSE.
// Returns 1 when motor status RUN signal becomes false.
// RETURN:
//    0-IN PROGRESS; 1-SUCCESS; negative num-FAULT CODE
int Stop_OneMotorNoRamp(BOOL firstentry, U8 motorID)
{
    if (*myMotors[motorID].ServiceMode) { return -10; } // motor in service mode

    if (firstentry)
    {
        motor_processTimer[motorID] = YAWM_STOP_DELAY;
        myMotors[motorID].MotorTargetSpeedPct = 0;
        *myMotors[motorID].Control->SpeedPctSP = 0;
        *myMotors[motorID].Control->Run = false;
    }

    if (*myMotors[motorID].MotorEnable)
    {
        if (!*myMotors[motorID].Status->Running)
        {
            return 1;   // SUCCESS
        }

        motor_processTimer[motorID] -= YAWM_TASK_SCANTIME;
        if (motor_processTimer[motorID] > 0) { return 0; }   // IN PROGRESS
        else
        {
            char ErrorDescriptionString[81];
            snprintf(ErrorDescriptionString, sizeof(ErrorDescriptionString), "Stop motor %u - Timeout", (motorID + 1));
            CustomLog_MakeEntry(MotorControlLog, &ErrorDescriptionString);
            return -1;  // FAULT - timeout
        }
    }
    
    return 0;
}


void Apply_OneBrake(U8 motorID)
{
    myMotors[motorID].Control->Brake = false;
}


void Apply_AllBrakes()
{
    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        Apply_OneBrake(i);
    }
}


void Release_OneBrake(U8 motorID)
{
    myMotors[motorID].Control->Brake = true;
}


void Release_AllBrakes()
{
    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        Release_OneBrake(i);
    }
}


// This function starts all motors without defining torque and speed and returns when all motors are running
// This function should be called as long as it returns 0.
// Each time set "firstentry" to TRUE for first call. For following calls, set it to FALSE.
// RETURN:
//    0-IN PROGRESS; 1-SUCCESS; negative num-FAULT CODE
int Run_AllMotors(BOOL firstentry)
{
    if (shutdown_Flag) { return 0; }

    int resultAll;

    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorEnable)
        {
            motor_processResult[i] = Run_OneMotor(firstentry, i);
        }
        else
        {
            motor_processResult[i] = 0;
        }

        if (motor_processResult[i] < 0)
        {
            return motor_processResult[i];  // FAULT
        }
    }

    resultAll = 0;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        resultAll += motor_processResult[i];
    }

    if (resultAll == MotorsEnabledCount) // all motors stopped
    {
        return 1;      // SUCCESS
    }

    return 0;   // IN PROGRESS
}



// This function starts all motors with specified speed and torque and returns 1 when
// all motors are running with more than min speed
// Each time set "firstentry" to TRUE for first call. For following calls, set it to FALSE.
// This function should be called as long as it returns 0
// INPUT:
//    Speed - [%] the desired yawing motor speed value; if Speed > 0 then yaw CW else CCW
//    Torque - [%] the desired yawing motor torque value
// RETURN:
//    0-IN PROGRESS; 1-SUCCESS; negative num-FAULT CODE
int Run_AllMotors_SpdTrq(BOOL firstentry, S16 Speed, S16 TorqueM, S16 TorqueG)
{
    Set_AllMotorsSpeedAndTorque(Speed, TorqueM, TorqueG);
    return Run_AllMotors(firstentry);
}


// This function stops all motors and returns 1, when all motors are stopped. Run signal is deactivated.
// Each time set "firstentry" to TRUE for first call. For following calls, set it to FALSE.
// RETURN:
//    0-IN PROGRESS; 1-SUCCESS; negative num-FAULT CODE
int Stop_AllMotors(BOOL firstentry)
{
    int resultAll;

    int i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorEnable)
        {
            motor_processResult[i] = Stop_OneMotor(firstentry, i);
        }
        else
        {
            motor_processResult[i] = 0;
        }

        if (motor_processResult[i] < 0)
        {
            return motor_processResult[i];  // FAULT
        }
    }

    resultAll = 0;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        resultAll += motor_processResult[i];
    }

    if (resultAll == MotorsEnabledCount) // all motors stopped
    {
        return 1;      // SUCCESS
    }

    return 0;   // IN PROGRESS
}


// This function stops all motors with specified torque and returns 1, when all motors are stopped. Run signal is deactivated.
// Each time set "firstentry" to TRUE for first call. For following calls, set it to FALSE.
// This function should be called as long as it returns 0
// INPUT:
//    Torque - [%] the desired yawing motor torque value
// RETURN:
//    0-IN PROGRESS; 1-SUCCESS; negative num-FAULT CODE
int Stop_AllMotors_Trq(BOOL firstentry, S16 Torque)
{
    if (firstentry) { Set_AllMotorsSpeedAndTorque(0, Torque, Torque); }
    return Stop_AllMotors(firstentry/*, timeout*/);
}


// This function stops all yaw motors without waiting them to slow down.
