// Handles yaw testing procedures.
void YawTesting()
{
    static U8 step;
    static int failCount;
    int result;


    if (V_YAWM_YawTest && !yawTest_Flag)   // start yaw brakes test procedure
    {
        step = 1;
        yawTest_Flag = true; // global indication that test procedure is running
        failCount = 0;
        InfoMessage("Yaw test started", 3);
    }
    else if (!V_YAWM_YawTest && yawTest_Flag) // manual cancelling of yaw test
    {
        Stop_AllMotorsNoRamp(true);
        Apply_AllBrakes();
        yawTest_Flag = false;
        InfoMessage("Yaw test canceled", 3);
        V_YAWM_YawTest = false;
        OS_VarDB_UpdateVariableByName("V_YAWM_YawTest", &V_YAWM_YawTest, sizeof(V_YAWM_YawTest));
    }
    else if (yawTest_Flag)
    {
        switch (step)
        {
            case 0:

                // do nothing
                break;

            case 1:

                Test_AllYawBrakes(true);
                step = 2;

                break;

            case 2:

                result = Test_AllYawBrakes(false);
                if (result == 1) { step = 3; }
                else if (result == -3)
                {
                    InfoMessage("Test not allowed", 3);
                    yawTest_Flag = false;
                    V_YAWM_YawTest = false;
                    OS_VarDB_UpdateVariableByName("V_YAWM_YawTest", &V_YAWM_YawTest, sizeof(V_YAWM_YawTest));
                }
                else if (result < 0)
                {
                    step = 3;
                    failCount++;
                }

                break;

            case 3:

                Test_AllMotors(true);
                step = 4;

                break;

            case 4:

                result = Test_AllMotors(false);
                if (result == 1) { step = 10; }
                else if (result == -3)
                {
                    InfoMessage("Test not allowed", 3);
                    yawTest_Flag = false;
                    V_YAWM_YawTest = false;
                    OS_VarDB_UpdateVariableByName("V_YAWM_YawTest", &V_YAWM_YawTest, sizeof(V_YAWM_YawTest));
                }
                else if (result < 0)
                {
                    step = 10;
                    failCount++;
                }

                break;

            case 10:

                if (failCount > 0)
                {
                    InfoMessage("Yaw test failed", 3);
                }
                else
                {
                    InfoMessage("Yaw test successful", 3);
                }

                yawTest_Flag = false;
                V_YAWM_YawTest = false;
                OS_VarDB_UpdateVariableByName("V_YAWM_YawTest", &V_YAWM_YawTest, sizeof(V_YAWM_YawTest));

                break;
        }
    }
}


// This function does the ramping for speed value to motor drives
static void SpeedRamping(U8 motorID)
{
    S16 rampStepUp = P_YAWM_SpeedRampUp / (1000 / YAWM_TASK_SCANTIME);
    S16 rampStepDown = P_YAWM_SpeedRampDown / (1000 / YAWM_TASK_SCANTIME);


    if (myMotors[motorID].MotorTargetSpeedPct < 0 && *myMotors[motorID].Control->SpeedPctSP < 0)  // CCW speed
    {
        if (*myMotors[motorID].Control->SpeedPctSP > myMotors[motorID].MotorTargetSpeedPct)       // Ramp Up
        {
            *myMotors[motorID].Control->SpeedPctSP -= rampStepUp;
            if (*myMotors[motorID].Control->SpeedPctSP <= myMotors[motorID].MotorTargetSpeedPct) // reached target
            {
                *myMotors[motorID].Control->SpeedPctSP = myMotors[motorID].MotorTargetSpeedPct;
            }
        }
        else if (*myMotors[motorID].Control->SpeedPctSP < myMotors[motorID].MotorTargetSpeedPct)     // Ramp Down
        {
            *myMotors[motorID].Control->SpeedPctSP += rampStepDown;
            if (*myMotors[motorID].Control->SpeedPctSP >= myMotors[motorID].MotorTargetSpeedPct) // reached target
            {
                *myMotors[motorID].Control->SpeedPctSP = myMotors[motorID].MotorTargetSpeedPct;
            }
        }
    }
    else if (myMotors[motorID].MotorTargetSpeedPct >= 0 && *myMotors[motorID].Control->SpeedPctSP >= 0)     // CW speed
    {
        if (*myMotors[motorID].Control->SpeedPctSP < myMotors[motorID].MotorTargetSpeedPct)       // Ramp Up
        {
            *myMotors[motorID].Control->SpeedPctSP += rampStepUp;
            if (*myMotors[motorID].Control->SpeedPctSP >= myMotors[motorID].MotorTargetSpeedPct) // reached target
            {
                *myMotors[motorID].Control->SpeedPctSP = myMotors[motorID].MotorTargetSpeedPct;
            }
        }
        else if (*myMotors[motorID].Control->SpeedPctSP > myMotors[motorID].MotorTargetSpeedPct)     // Ramp Down
        {
            *myMotors[motorID].Control->SpeedPctSP -= rampStepDown;
            if (*myMotors[motorID].Control->SpeedPctSP <= myMotors[motorID].MotorTargetSpeedPct) // reached target
            {
                *myMotors[motorID].Control->SpeedPctSP = myMotors[motorID].MotorTargetSpeedPct;
            }
        }
    }
    else     // ramp down speed when target is CW and setpoint is CCW or vice versa. It means it needs to change direction and that needs ramp down first to stop previous direction
    {
        if (*myMotors[motorID].Control->SpeedPctSP < 0)       // Ramp Down (CCW speed)
        {
            *myMotors[motorID].Control->SpeedPctSP += rampStepDown;
            if (*myMotors[motorID].Control->SpeedPctSP >= myMotors[motorID].MotorTargetSpeedPct) // reached target
            {
                *myMotors[motorID].Control->SpeedPctSP = myMotors[motorID].MotorTargetSpeedPct;
            }
        }
        else       // Ramp Down (CW speed)
        {
            *myMotors[motorID].Control->SpeedPctSP -= rampStepDown;
            if (*myMotors[motorID].Control->SpeedPctSP <= myMotors[motorID].MotorTargetSpeedPct) // reached target
            {
                *myMotors[motorID].Control->SpeedPctSP = myMotors[motorID].MotorTargetSpeedPct;
            }
        }
    }
}


// This function writes analog setpoint(speed and torque) values to motor drives.
static void UpdateAnalogSP()
{
    U8 i;
    for (i = 0; i < MOTOR_COUNT; i++)
    {
        if (*myMotors[i].MotorEnable)
        {
            if (*myMotors[i].ServiceMode)     // use service setpoints in service mode
            {
                *myMotors[i].Control->SpeedPctSP = V_YAWM_Service_SpeedRef;
                *myMotors[i].Control->TorqueLimMotor = V_YAWM_Service_MotorTorqueLim;
                *myMotors[i].Control->TorqueLimGen = V_YAWM_Service_GeneratorTorqueLim;
            }
            else
            {
                if (*myMotors[i].Control->Run) { SpeedRamping(i); }
                else { *myMotors[i].Control->SpeedPctSP = 0; }

                *myMotors[i].Control->TorqueLimMotor = myMotors[i].MotorTorqueLimMotor;
                *myMotors[i].Control->TorqueLimGen = myMotors[i].MotorTorqueLimGen;
            }
        }
        else
        {
            *myMotors[i].Control->SpeedPctSP = 0;
            *myMotors[i].Control->TorqueLimMotor = 0;
            *myMotors[i].Control->TorqueLimGen = 0;
        }
    }
}


// This calculates yaw angle based on yaw motor rotations
static void CalcYawAngle()
{
    static BOOL YawAngleInitialized = false;
    static S32 YawTwistDeg_Initial;
    static U8 P_YAWM_YawAngleSourceMotorId_prev = 0;

    // detect when yaw angle source motor id changed and make new initialization
    if (P_YAWM_YawAngleSourceMotorId != P_YAWM_YawAngleSourceMotorId_prev)
    {
        P_YAWM_YawAngleSourceMotorId_prev = P_YAWM_YawAngleSourceMotorId;
        YawAngleInitialized = false;
    }

    if (YawAngleInitialized)
    {
        S32 rotations_change = *myMotors[P_YAWM_YawAngleSourceMotorId - 1].Status->Rotations - myMotors[P_YAWM_YawAngleSourceMotorId - 1].MotorPosition_Initial;
        S32 new_angle = (rotations_change * P_YAWM_YawDegPerRotation) / 10000;
        V_YAWM_YawAngleMotor = YawTwistDeg_Initial + new_angle;
    }
    else
    {
        // initializing yaw angle calculation based on motor rotation value
        if (*myMotors[P_YAWM_YawAngleSourceMotorId - 1].MotorState == YAWM_MOTOR_READY)
        {
            // save initial yaw twist angle from yaw encoder
            YawTwistDeg_Initial = V_YAW_YawAngleEncoder;
            // save initial yaw motor encoder revolutions count
            myMotors[P_YAWM_YawAngleSourceMotorId - 1].MotorPosition_Initial = *myMotors[P_YAWM_YawAngleSourceMotorId - 1].Status->Rotations;
            YawAngleInitialized = true;
        }
    }
}


// check brake feedback error and write it to the log
static void BrakeFeedbackError_Log()
{
    static BOOL errorStatus_prev = false;
    char LogString[81];

    U8 errorStatus = OS_StatusCodeActive(5358);
    if (errorStatus && !errorStatus_prev)   // errorStatus_prev is used to write into the log only at the moment of error activation
    {
        int i;
        for (i = 0; i < MOTOR_COUNT; i++)
        {
            if (*myMotors[i].Control->BrakeDO && !*myMotors[i].Status->BrakeFeedback)
            {
                snprintf(LogString, sizeof(LogString), "Brake %u feedback stays OFF", (i + 1));
                CustomLog_MakeEntry(MotorControlLog, &LogString);
            }
            else if (!(*myMotors[i].Control->BrakeDO) && *myMotors[i].Status->BrakeFeedback)
            {
                snprintf(LogString, sizeof(LogString), "Brake %u feedback stays ON", (i + 1));
                CustomLog_MakeEntry(MotorControlLog, &LogString);
            }
        }
    }
    errorStatus_prev = errorStatus;
}

//++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++
//++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++++




static STATUS LocalCtrl(U32 Interval)
{
    STATUS LocalStatus = 0;


#if defined(YAWM_DEBUG) || defined(INCLUDE_DEBUG)

    // simulation for drives 2 - 8
    U8 i;
    for (i = 1; i < MOTOR_COUNT; i++)
    {
        // simulate actual speed percent and rpm
        if (*myMotors[i].Control->Run)
        {
            *myMotors[i].Status->SpeedPct = *myMotors[i].Control->SpeedPctSP;
            *myMotors[i].Status->SpeedRpm = *myMotors[i].Control->SpeedPctSP / 10;     // 100% = 10000(% scale 100) / 10 = 1000 rpm
        }
        else
        {
            *myMotors[i].Status->SpeedPct = 0;
            *myMotors[i].Status->SpeedRpm = 0;
        }
    }
#endif


    YawMotorBrakeControl();
    YawMotorFanControl();
    Check_Drives();
    ReadStatusWord();
    WriteControlWord();
    UpdateAnalogSP();
    CalcMotorPosition();
    UpdateCANopenStates();
    MotorControl_Log();
    AutomaticDriveResetHandling();
    CheckForCANopenReset();
    CheckForDrivesReset();
    YawTesting();
    CalcYawAngle();
    UpdateMotTemperatures();
    BrakeFeedbackError_Log();


    // reloading parameters from menu
    if (V_YAWM_LoadParameters)
    {
        V_YAWM_LoadParameters = false;
        OS_VarDB_UpdateVariableByName("V_YAWM_LoadParameters", &V_YAWM_LoadParameters, sizeof(V_YAWM_LoadParameters));
        LoadParameters();
        InfoMessage("Parameters reloaded", 1);
    }

    // reload motor group configuration
    //----------------------------------------------------------------------------------
    if (V_YAWM_LoadGroupSetup)
    {
        LoadMotorGroupSetup();
        V_YAWM_LoadGroupSetup = false;
        OS_VarDB_UpdateVariableByName("V_YAWM_LoadGroupSetup", &V_YAWM_LoadGroupSetup, sizeof(V_YAWM_LoadGroupSetup));
        InfoMessage("Group setup loaded", 2);
    }


    // reset motor positions from menu
    //----------------------------------------------------------------------------------
    if (V_YAWM_ResetMotorPosition)
    {
        V_YAWM_ResetMotorPosition = false;
        OS_VarDB_UpdateVariableByName("V_YAWM_ResetMotorPosition", &V_YAWM_ResetMotorPosition, sizeof(V_YAWM_ResetMotorPosition));
        ResetAllMotorPositions();
        InfoMessage("Yaw motor positions reset", 1);
    }

    return LocalStatus;
}

static STATUS ShutdownCtrl(U8 ModuleState, U8* DoneState, U32 Interval)
{
    STATUS LocalStatus = 0;

    LocalStatus = LocalCtrl(Interval);
    STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);


    // stop all yaw motors and apply brakes before shutdown
    shutdown_Flag = true;
    if (Stop_AllMotorsShutdown() == 0)
    {
        return LocalStatus;
    }


    switch (ModuleState)
    {
        case AS_SHUTDOWN:
        {
            // Activate "Manual Shutdown" status code

            *DoneState = AS_SHUTDOWN;
            break;
        }
        case AS_REBOOT:
        {

            *DoneState = AS_REBOOT;
            break;
        }
        case AS_SHUTDOWN_FAST:
        {

            *DoneState = AS_SHUTDOWN_FAST;
            break;
        }
        default:
        {
            *DoneState = ModuleState;
            break;
        }
    }

    return LocalStatus;
}

//-----------------------------------------------------------------------
// MAIN CALL             MAIN CALL               MAIN CALL
//-----------------------------------------------------------------------

STATUS YawMotorControl_MK1(U8 ModuleState, U8* DoneState , U32 Interval)
{
    STATUS LocalStatus = 0;

#ifdef READ_VARS
    // Read input data
    LocalStatus = InputReferenceRoutine(ModuleState);
    STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif
#ifdef COMMON_VDB_READ
    LocalStatus = ReadVdbWindow(ModuleState);
    STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif


    switch (ModuleState)
    {
            //__________________________________________________________________________
        case APP_RUN:
        {
         #ifdef FUNCTION_BLOCKS_PRE_LOCAL_CONTROL
            LocalStatus = FunctionBlocksPreLocalCtrl( Interval );
            STATUS_LINE_VAR_RETURN_VALUE( LocalStatus );
         #endif

            LocalStatus = LocalCtrl(Interval);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
        
         #ifdef FUNCTION_BLOCKS_POST_LOCAL_CONTROL
            LocalStatus = FunctionBlocksPostLocalCtrl( Interval );
            STATUS_LINE_VAR_RETURN_VALUE( LocalStatus );
         #endif

#ifdef WRITE_VARS
            // Write Output data
            LocalStatus = OutputReferenceRoutine(ModuleState);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

#ifdef COMMON_VDB_WRITE
            LocalStatus = WriteVdbWindow(ModuleState);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

            *DoneState = APP_RUN;
            break;
        }
        //__________________________________________________________________________
        case APP_INIT1:
        {
            // Version check
            LocalStatus = OS_ValidateAPI(API_VERSION_MAJOR,
                                         API_VERSION_MINOR,
                                         OS_LinkTime,
                                         ReleaseTag,
                                         __MODULE__
                                        );
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);

            Init_Structures_From_Conf_File();

#ifdef CREATE_VARDB_VARS
            LocalStatus = CreateVarDbVars();
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

#ifdef CREATE_MENU
            LocalStatus = YawMotorControl_MK1MenuAppInit(ModuleState, GetMemPool());
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);

#ifdef MULTIPLEXIBLE_MENU
            LocalStatus = MenuArraysAppInit(ModuleState, GetMemPool());
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif
#endif

#ifdef CREATE_VARDB_ARRAY_VARS
            LocalStatus = CreateVdbArrays(GetMemPool());
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif


#ifdef CREATE_IO_VARS
            LocalStatus = CreateIOVars();
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

            *DoneState = APP_INIT1;

            break;
        }
        //__________________________________________________________________________
        case APP_INIT2:
        {
#ifdef CREATE_MENU
#ifdef MULTIPLEXIBLE_MENU
            LocalStatus = MenuArraysAppInit(ModuleState, GetMemPool());
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif
#endif

#ifdef CREATE_ALIASES
            size_t ErrorEntry = 0;
            LocalStatus = OS_VarDB_CreateAliases(AliasVars, sizeof(AliasVars) / sizeof(AliasVars[0]), &ErrorEntry);
            STATUS_LINE_VAR_RETURN_CONST(LocalStatus, ErrorEntry);
#endif

#ifdef VERIFY_ARRAY
            LocalStatus = VerifyArray(GetMemPool());
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

#ifdef VERIFY_VARIABLES
            LocalStatus = LocalIoCheck();
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

#ifdef CREATE_BUTTONS
            LocalStatus = CreateButtons();
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

            *DoneState = APP_INIT2;

            break;
        }
        //__________________________________________________________________________
        case APP_INIT3:
        {
#ifdef CREATE_SUMMATIONS
            LocalStatus = CreateSummations();
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

#ifdef WRITE_VARS
            LocalStatus = InitOutputVars();
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

#ifdef CREATE_STATUS_CODES
            LocalStatus = LocalStatusCodeInit();
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

#ifdef CREATE_IO_VARS
            YawMotorControl_MK1SetLockValues();
#endif

            *DoneState = APP_INIT3;

            break;
        }
        //__________________________________________________________________________
        case APP_INIT4:
        {
#ifdef CREATE_MENU
            LocalStatus = YawMotorControl_MK1MenuAppInit(ModuleState, GetMemPool());
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);

#ifdef MULTIPLEXIBLE_MENU
            LocalStatus = MenuArraysAppInit(ModuleState, GetMemPool());
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif
#endif

            *DoneState = APP_INIT4;

            break;
        }
        //__________________________________________________________________________
        case APP_INIT5:
        {
#ifdef VALIDATE_HASH
            LocalStatus = ValidateHash(YawMotorControl_MK1_copyright, MODULE_NAME, YawMotorControl_MK1_initialValues);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

         #ifdef INIT_FUNCTION_BLOCKS
            LocalStatus = FunctionBlocksInit( Interval );
            STATUS_LINE_VAR_RETURN_VALUE( LocalStatus );
         #endif


            LocalStatus = Initialize();
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);

            *DoneState = APP_INIT5_DONE;

            break;
        }
        //__________________________________________________________________________
        //Other initialization round can be inserted here
        //__________________________________________________________________________
        case AS_SHUTDOWN:
        {
            LocalStatus = ShutdownCtrl(ModuleState, DoneState, Interval);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);

#ifdef WRITE_VARS
            // Write Output data
            LocalStatus = OutputReferenceRoutine(ModuleState);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

#ifdef COMMON_VDB_WRITE
            LocalStatus = WriteVdbWindow(ModuleState);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

            break;
        }
        //__________________________________________________________________________
        case AS_REBOOT:
        {
            LocalStatus = ShutdownCtrl(ModuleState, DoneState, Interval);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);

#ifdef WRITE_VARS
            // Write Output data
            LocalStatus = OutputReferenceRoutine(ModuleState);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

#ifdef COMMON_VDB_WRITE
            LocalStatus = WriteVdbWindow(ModuleState);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

            break;
        }
        //__________________________________________________________________________
        case AS_SHUTDOWN_FAST:
        {
            LocalStatus = ShutdownCtrl(ModuleState, DoneState, Interval);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);

#ifdef WRITE_VARS
            // Write Output data
            LocalStatus = OutputReferenceRoutine(ModuleState);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

#ifdef COMMON_VDB_WRITE
            LocalStatus = WriteVdbWindow(ModuleState);
            STATUS_LINE_VAR_RETURN_VALUE(LocalStatus);
#endif

            break;
        }
        default:
        {
            *DoneState = ModuleState;

            break;
        }
    }
    return OS_SUCCESS;
}
